import { useNavigate } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'


const navigate = useNavigate();

// Delete
export const deleteRow = async (endpoint, id) => {
    try {
        await constFlaskURL.delete(`/roads?id=${id}`);
        fetchTableData()
    } catch (error) {
        console.log(error);
    } 
}

// Get
export const getRow = async (endpoint, id) => {
    try {
        await constFlaskURL.get(`${endpoint}?id=${id}`);
        navigate(`${endpoint}/edit/${id}`);
    } catch (error) {
        console.log(error);
    } 
}
